class Solution {
    public:
        int power(int a, int n) {
            long long res = 1;
            while (n > 0) {
                if (n % 2 == 1) {
                    res *= a;
                }
                a *= a;
                n /= 2;
            }
            return res;
        }
    };

int main() {
    Solution solution;
    int a, n;
    cin >> a >> n;
    cout << solution.power(a, n);
    return 0;
}

