class Solution:
    def power(self, a: int, n: int) -> int:
        res = 1
        while n > 0:
            if n % 2 == 1:
                res *= a
            a *= a
            n //= 2
        return res

import sys

def main():
    solution = Solution()
    a, n = map(int, input().split())
    print(solution.power(a, n))

